import json
import pickle

def lambda_handler(event, context):
    try:
        # Deserialize the JSON payload
        payload = json.loads(event['body'])
        
        # Process the user action (example processing)
        user_action = payload.get('action')
        user_data = payload.get('data')
        
        # Perform some processing based on user action
        if user_action == 'create':
            # Handle create action
            response = f"Created user with data: {user_data}"
        elif user_action == 'update':
            # Handle update action
            response = f"Updated user with data: {user_data}"
        else:
            response = "Unknown action"

        # Serialize response using pickle for fast serialization
        serialized_response = pickle.dumps(response)
        
        return {
            'statusCode': 200,
            'body': serialized_response
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': str(e)
        }